import{_ as i,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"32A. Endorsed Midwife","description":"","frontmatter":{"title":"32A. Endorsed Midwife","eba":"Nurses and Midwives 2024-2028","topics":["preliminary","definitions","staffing"]},"headers":[],"relativePath":"ebas/nurses-midwives/allowances/32A-endorsed-midwife.md","filePath":"ebas/nurses-midwives/allowances/32A-endorsed-midwife.md"}'),d={name:"ebas/nurses-midwives/allowances/32A-endorsed-midwife.md"};function s(r,e,t,l,c,f){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_32a-endorsed-midwife" tabindex="-1">32A. Endorsed Midwife <a class="header-anchor" href="#_32a-endorsed-midwife" aria-label="Permalink to &quot;32A. Endorsed Midwife&quot;">​</a></h1><p><strong>32A.1</strong> Definition</p><p>An Endorsed Midwife is a Midwife who:</p><p><strong>(a)</strong> Currently holds a NMBA endorsement for scheduled medicines for midwives; and</p><p><strong>(b)</strong> Is contracted to or otherwise required by the Employer to undertake any of the core functions of an Endorsed Midwife, as identified by the Nursing and Midwifery Board of Australia.</p><p><strong>32A.2</strong> Entitlement – from 1 June 2025</p><p><strong>(a)</strong> A Midwife who meets the definition of an Endorsed Midwife in accordance with 32A.1(a) and (b) above will be paid, in addition to their salary, in accordance with the &quot;Endorsed Midwife&quot; rate in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a>, Part 2 on all hours, including overtime.</p><p><strong>(b)</strong> This allowance is to be included as salary for all employment related purposes including superannuation and leave entitlements.</p><p><strong>32A.3</strong> Interaction between Qualification Allowance and Endorsed Midwife Allowance</p><p>An Endorsed Midwife who is in receipt of an allowance under this clause 32A is not precluded from receiving a Qualification Allowance under <a href="/eba/ebas/nurses-midwives/allowances/31-qualification-allowance.html">clause 31</a> in addition.</p>',10)])])}const u=i(d,[["render",s]]);export{p as __pageData,u as default};
